// StoreLeads CSV rows are already ecom + pre-filtered by Julia to the ecom ICP.
// We still run the disqualifier (dropship/brick) and tag secondary_ecom.
// Full 80K/$70 vs 60-100K/$27 gating happens in Phase 4 scoring, not here.
const DROPSHIP = [/\bdropship(ping)?\b/i, /\baliexpress\b/i, /\bprint on demand\b/i, /\bpod\b/i];
function hostname(url){ try { return new URL(url.startsWith('http')?url:`https://${url}`).hostname.replace(/^www\./,''); } catch { return null; } }
const out = [];
for (const item of $input.all()) {
  const r = item.json;
  const domain = hostname(r.domain || r.Domain || r.url || r.URL || '');
  if (!domain) continue;
  const name = r.company_name || r.name || r.Store || r.merchant || null;
  const isDrop = DROPSHIP.some(re => re.test(`${name || ''} ${r.description || ''}`));
  out.push({ json: {
    domain,
    company_name: name,
    founder_name: r.founder_name || r.owner || null,
    founder_email: r.email || r.Email || null,
    founder_linkedin_url: r.linkedin || null,
    founder_ig_handle: r.instagram || r.ig || null,
    source: 'storeleads',
    source_metadata: {
      list_size: r.list_size ? Number(r.list_size) : null,
      aov: r.aov ? Number(r.aov) : null,
      platform: r.platform || null,
      imported_from: $('New CSV in Drive Folder').item.json.name || null,
      routing_confidence: 'high'
    },
    icp_tier: isDrop ? 'disqualified' : 'secondary_ecom',
    is_archived: isDrop,
    archive_reason: isDrop ? 'dropshipper' : null
  }});
}
return out;
